tasks.solution:
// Part 1 & 2 — Jenkins Credential usage in Jenkinsfile:
stage('Example Secret Usage') {
    steps {
        withCredentials([string(credentialsId: 'db-password', variable: 'DB_PASS')]) {
            sh 'echo "DB_PASS is set: ${#DB_PASS} chars"'  // prints length, not value
            // Jenkins automatically masks DB_PASS — any accidental echo shows '****'
        }
    }
}

// Console Output:
// [Example Secret Usage] $ echo "DB_PASS is set: 14 chars"
// DB_PASS is set: 14 chars
// (Value 's3cr3tP@ssw0rd' NEVER appears in the log)

// Part 3 — Create /home/ec2-user/app.env on EC2 (via SSH, not via pipeline):
ssh ec2-user@<EC2_IP>
cat > /home/ec2-user/app.env << 'EOF'
DB_PASSWORD=s3cr3tP@ssw0rd
API_KEY=my-api-key-12345
EOF
chmod 600 /home/ec2-user/app.env   # restrict file permissions

// Part 4 — Updated docker-compose.yml on EC2:
cat > /home/ec2-user/docker-compose.yml << 'EOF'
services:
  web:
    image: ${IMAGE}
    ports:
      - "80:8080"
    restart: always
    env_file: /home/ec2-user/app.env
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:8080/health"]
      interval: 10s
      timeout: 3s
      retries: 3
EOF

// Verify the running container sees the secret:
docker exec <container-name> printenv DB_PASSWORD
// Output: s3cr3tP@ssw0rd
// (This runs ON the EC2 server — the secret is only visible there)

