tasks.solution:
// Step 1 — Broken index.js (health endpoint returns 500):
const http = require('http');
const server = http.createServer((req, res) => {
  if (req.url === '/health') {
    res.writeHead(500);
    res.end('Intentional failure');
    return;
  }
  res.writeHead(200);
  res.end('Hello from container!');
});
server.listen(8080, () => console.log('Listening on port 8080'));

// Step 2 — Push:
git add index.js
git commit -m "Break health endpoint for rollback test"
git push

// Expected Jenkins behaviour:
// Checkout, Build, Test — all green (test does not test /health)
// Build Image, Push to ECR — green (image is built and pushed)
// Deploy & Verify:
//   'docker compose up -d --wait' starts the broken container
//   Healthcheck runs: curl -f http://localhost:8080/health → exits 1 (HTTP 500)
//   After retries (3 x 10s = 30s), Compose exits non-zero
//   SSH returns non-zero → Jenkins stage fails → turns RED
//   post { failure { ... } } block runs:
//     reads last_good_tag (the SHA of the last working build)
//     runs: export IMAGE=registry/myapp:<previous-sha>
//     docker compose up -d --wait (with the old, working image)
//     Old image passes healthcheck → exits 0 → rollback complete

// Step 3 — Verify on EC2:
// docker ps → shows the OLD container running the previous-SHA image
// cat /home/ec2-user/last_good_tag → shows the previous SHA (unchanged by failed deploy)
// curl http://localhost:80/ → returns 'Hello from container!' (service still up)
// curl http://localhost:80/health → returns 'OK' (old image's healthy endpoint)

// Clean up: revert the break and push to restore normal pipeline operation.
